#!/usr/bin/env python3
"""
InsideScan — локальный HTTPS сканер штрихкодов
Читает EAN-13, QR, Code128, DataMatrix и всё остальное.

Установка:  pip install pynput websockets qrcode
Запуск:     python InsideScan.py
"""
import asyncio, http, json, os, socket, ssl, subprocess, sys, threading, time

try:
    import pyautogui; pyautogui.FAILSAFE = True
    _PYAUTOGUI = True
except ImportError:
    _PYAUTOGUI = False
    pyautogui = None
try:
    from websockets.legacy.server import serve
except ImportError:
    print("\u274c  pip install pyautogui websockets qrcode"); sys.exit(1)

PORT         = 8765
PRESS_ENTER  = True
TYPE_DELAY   = 0.3
KEY_INTERVAL = 0.03
CERT_FILE    = "insidescan_cert.pem"
KEY_FILE     = "insidescan_key.pem"

G="\033[92m"; Y="\033[93m"; R="\033[91m"
C="\033[96m"; B="\033[1m";  D="\033[2m"; X="\033[0m"

scan_count = 0
connected_clients = set()
_server_ip = "127.0.0.1"

