# ══════════════════════════════════════════════════════════════
# SSL
# ══════════════════════════════════════════════════════════════
def create_cert(ip):
    if os.path.exists(CERT_FILE) and os.path.exists(KEY_FILE):
        return True
    print(f"{Y}Создаю SSL сертификат...{X}")
    cmd = ["openssl","req","-x509","-newkey","rsa:2048",
           "-keyout",KEY_FILE,"-out",CERT_FILE,"-days","365","-nodes",
           "-subj",f"/CN={ip}","-addext",f"subjectAltName=IP:{ip},IP:127.0.0.1"]
    try:
        r = subprocess.run(cmd, capture_output=True, timeout=15)
        if r.returncode == 0:
            print(f"{G}\u2713 Сертификат создан{X}"); return True
    except (FileNotFoundError, subprocess.TimeoutExpired): pass
    try:
        from cryptography import x509
        from cryptography.x509.oid import NameOID
        from cryptography.hazmat.primitives import hashes, serialization
        from cryptography.hazmat.primitives.asymmetric import rsa
        import datetime, ipaddress
        key = rsa.generate_private_key(public_exponent=65537, key_size=2048)
        name = x509.Name([x509.NameAttribute(NameOID.COMMON_NAME, ip)])
        cert = (x509.CertificateBuilder()
            .subject_name(name).issuer_name(name).public_key(key.public_key())
            .serial_number(x509.random_serial_number())
            .not_valid_before(datetime.datetime.utcnow())
            .not_valid_after(datetime.datetime.utcnow()+datetime.timedelta(days=365))
            .add_extension(x509.SubjectAlternativeName([
                x509.IPAddress(ipaddress.IPv4Address(ip)),
                x509.IPAddress(ipaddress.IPv4Address("127.0.0.1")),
            ]),critical=False).sign(key, hashes.SHA256()))
        with open(KEY_FILE,"wb") as f:
            f.write(key.private_bytes(serialization.Encoding.PEM,
                serialization.PrivateFormat.TraditionalOpenSSL, serialization.NoEncryption()))
        with open(CERT_FILE,"wb") as f:
            f.write(cert.public_bytes(serialization.Encoding.PEM))
        print(f"{G}\u2713 Сертификат создан{X}"); return True
    except ImportError: pass
    print(f"{R}\u274c Нет openssl. pip install cryptography{X}"); return False

def make_ssl_ctx():
    ctx = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    ctx.load_cert_chain(CERT_FILE, KEY_FILE)
    return ctx

