# HTML
# ══════════════════════════════════════════════════════════════
def get_html(ip):
    wss = f"wss://{ip}:{PORT}/ws"
    return (
        """<!DOCTYPE html>
<html lang="ru">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0,user-scalable=no">
<meta name="apple-mobile-web-app-capable" content="yes">
<title>InsideScan</title>
<!-- jsQR: QR fallback -->
<script>""" + JSQR_JS + """</script>
<!-- ZXing-WASM: EAN-13, Code128, DataMatrix, QR... -->
<script>""" + ZXING_JS + """</script>
<script>
// Point ZXing to our local /zxing.wasm endpoint
ZXingWASM.setZXingModuleOverrides({locateFile:function(f){return'/zxing.wasm';}});
</script>
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{--bg:#080810;--surface:#10101c;--border:#1c1c30;--accent:#00ff88;--muted:#484870;--danger:#ff4466}
body{background:var(--bg);color:#e8e8f0;font-family:-apple-system,sans-serif;height:100dvh;display:flex;flex-direction:column;overflow:hidden}
.topbar{display:flex;align-items:center;gap:10px;padding:11px 16px;background:var(--surface);border-bottom:1px solid var(--border);flex-shrink:0}
.dot{width:8px;height:8px;border-radius:50%;background:var(--muted);flex-shrink:0}
.dot.green{background:var(--accent);box-shadow:0 0 8px var(--accent);animation:pulse 1.5s infinite}
.dot.yellow{background:#ffcc00}.dot.red{background:var(--danger)}
@keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}
.st{font-size:12px;color:var(--muted);font-family:'Courier New',monospace;flex:1}
.cnt{background:var(--accent);color:#000;font-family:'Courier New',monospace;font-size:11px;font-weight:700;padding:2px 8px;border-radius:2px;min-width:26px;text-align:center}
.cam{flex:1;position:relative;background:#000;overflow:hidden;min-height:0}
#video{width:100%;height:100%;object-fit:cover;display:block}
#canvas{display:none}
.ov{position:absolute;inset:0;pointer-events:none}
.frame{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:88%;height:25%}
.cc{position:absolute;width:18px;height:18px;border-color:var(--accent);border-style:solid}
.cc.tl{top:0;left:0;border-width:2px 0 0 2px}.cc.tr{top:0;right:0;border-width:2px 2px 0 0}
.cc.bl{bottom:0;left:0;border-width:0 0 2px 2px}.cc.br{bottom:0;right:0;border-width:0 2px 2px 0}
.beam{position:absolute;top:50%;left:3%;right:3%;height:2px;transform:translateY(-50%);background:linear-gradient(90deg,transparent,var(--accent) 15%,var(--accent) 85%,transparent);box-shadow:0 0 12px var(--accent);animation:blink 2s ease-in-out infinite}
@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}
.flash{position:absolute;inset:0;background:var(--accent);opacity:0;pointer-events:none}
.flash.go{animation:fl .2s ease-out forwards}
@keyframes fl{0%{opacity:.4}100%{opacity:0}}
.toast{position:absolute;bottom:14px;left:50%;transform:translateX(-50%) translateY(72px);background:var(--surface);border:1px solid var(--border);border-left:3px solid var(--accent);padding:8px 14px;font-family:'Courier New',monospace;white-space:nowrap;max-width:93vw;overflow:hidden;text-overflow:ellipsis;transition:transform .28s cubic-bezier(.34,1.5,.64,1);pointer-events:none;color:var(--accent)}
.toast.show{transform:translateX(-50%) translateY(0)}
.tf{font-size:9px;opacity:.5;display:block;margin-bottom:1px;letter-spacing:1.5px}
.tv{font-size:14px}
.bar{padding:10px 16px;background:var(--surface);border-top:1px solid var(--border);flex-shrink:0;display:flex;align-items:center;justify-content:space-between}
.bip{font-family:'Courier New',monospace;font-size:10px;color:var(--muted)}
.br{display:flex;align-items:center;gap:8px}
.lbl{font-size:10px;color:var(--muted);font-family:'Courier New',monospace}
#etb{background:none;border:1px solid var(--border);color:var(--muted);font-family:'Courier New',monospace;font-size:10px;padding:4px 10px;cursor:pointer;border-radius:2px}
#etb.on{border-color:var(--accent);color:var(--accent)}
</style>
</head>
<body>
<div class="topbar">
  <div class="dot" id="dot"></div>
  <div class="st" id="st">\u0417\u0430\u043f\u0443\u0441\u043a...</div>
  <div class="cnt" id="cnt">0</div>
</div>
<div class="cam">
  <video id="video" autoplay muted playsinline></video>
  <canvas id="canvas"></canvas>
  <div class="ov">
    <div class="frame">
      <div class="cc tl"></div><div class="cc tr"></div>
      <div class="cc bl"></div><div class="cc br"></div>
      <div class="beam"></div>
    </div>
  </div>
  <div class="flash" id="flash"></div>
  <div class="toast" id="toast">
    <span class="tf" id="tfmt"></span>
    <span class="tv" id="tval"></span>
  </div>
</div>
<div class="bar">
  <div class="bip">\U0001f512 InsideScan</div>
  <div class="br">
    <span class="lbl">ENTER</span>
    <button id="etb" class="on" onclick="toggleEnter()">\u0412\u041a\u041b</button>
  </div>
</div>
<script>
var WS_URL='""" + wss + """';
var ws, n=0, lastCode='', lastTime=0, pressEnter=true, scanning=false;
var nativeDetector=null, zxingReady=false;
var canvas=document.getElementById('canvas');
var ctx=canvas.getContext('2d',{willReadFrequently:true});

// ── WebSocket ─────────────────────────────────────────────────
function connect(){
  ws=new WebSocket(WS_URL);
  ws.onopen=function(){setStatus('green','InsideScan \u00b7 \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0435\u043d\u043e \u2713')};
  ws.onclose=function(){setStatus('red','\u041d\u0435\u0442 \u0441\u0432\u044f\u0437\u0438...');setTimeout(connect,2000)};
  ws.onerror=function(){};
}
function setStatus(c,t){
  document.getElementById('dot').className='dot '+c;
  document.getElementById('st').textContent=t;
}

// ── Camera ────────────────────────────────────────────────────
async function startCamera(){
  setStatus('yellow','\u0417\u0430\u043f\u0443\u0441\u043a...');
  try{
    var stream=await navigator.mediaDevices.getUserMedia({
      video:{facingMode:'environment',width:{ideal:1280},height:{ideal:720}}
    });
    var v=document.getElementById('video');
    v.srcObject=stream;
    await new Promise(function(r){v.onloadedmetadata=r});
    await v.play();

    // Init native BarcodeDetector if available
    if('BarcodeDetector' in window){
      try{
        var fmts=await BarcodeDetector.getSupportedFormats();
        nativeDetector=new BarcodeDetector({formats:fmts});
      }catch(e){}
    }

    scanning=true;
    setStatus('green','InsideScan \u00b7 \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0435\u043d\u043e \u2713');
    requestAnimationFrame(scanFrame);
  }catch(e){setStatus('red','\u041a\u0430\u043c\u0435\u0440\u0430: '+e.message);}
}

// ── Scan loop ─────────────────────────────────────────────────
var scanBusy=false;
function scanFrame(){
  if(!scanning) return;
  var v=document.getElementById('video');
  if(v.readyState===v.HAVE_ENOUGH_DATA && !scanBusy){
    canvas.width=v.videoWidth;
    canvas.height=v.videoHeight;
    ctx.drawImage(v,0,0);
    doScan(v);
  }
  requestAnimationFrame(scanFrame);
}

function doScan(v){
  // 1. Native BarcodeDetector (fastest, all formats)
  if(nativeDetector){
    scanBusy=true;
    nativeDetector.detect(v).then(function(r){
      if(r&&r.length>0) fire(r[0].rawValue,r[0].format.toUpperCase());
    }).catch(function(){}).finally(function(){scanBusy=false;});
    return;
  }

  // 2. ZXing-WASM (EAN-13, Code128, DataMatrix, QR, всё)
  try{
    var img=ctx.getImageData(0,0,canvas.width,canvas.height);
    scanBusy=true;
    ZXingWASM.readBarcodesFromImageData(img,{
      tryHarder:false,
      textMode:'Plain',
      formats:['EAN-13','EAN-8','QR Code','Code 128','Code 39','UPC-A','UPC-E','DataMatrix','Aztec','ITF','PDF417']
    }).then(function(results){
      if(results&&results.length>0){
        var r=results[0];
        var fmt=r.format.replace(/ /g,'-').toUpperCase();

        // Rebuild string from raw bytes — the only reliable way to get GS (0x1d)
        // ZXing bytes field is Uint8Array with actual barcode bytes
        var rawText='';
        if(r.bytes && r.bytes.length>0){
          for(var i=0;i<r.bytes.length;i++){
            var b=r.bytes[i];
            rawText+=String.fromCharCode(b);
          }
        } else {
          // fallback: r.text in Plain mode, replace common GS substitutes
          rawText=r.text;
        }

        fire(rawText, fmt);
      }
    }).catch(function(){}).finally(function(){scanBusy=false;});
    return;
  }catch(e){}

  // 3. jsQR (QR only, synchronous fallback)
  var img=ctx.getImageData(0,0,canvas.width,canvas.height);
  var c=jsQR(img.data,img.width,img.height,{inversionAttempts:'dontInvert'});
  if(c) fire(c.data,'QR_CODE');
}

// ── Fire code ─────────────────────────────────────────────────
function fire(code,fmt){
  var now=Date.now();
  if(code===lastCode&&now-lastTime<3000) return;
  lastCode=code; lastTime=now;
  var f=document.getElementById('flash');
  f.classList.remove('go'); void f.offsetWidth; f.classList.add('go');
  if(navigator.vibrate) navigator.vibrate(55);
  n++; document.getElementById('cnt').textContent=n;
  document.getElementById('tfmt').textContent=fmt;
  document.getElementById('tval').textContent=code;
  var t=document.getElementById('toast');
  t.classList.add('show'); setTimeout(function(){t.classList.remove('show')},2500);
  if(ws&&ws.readyState===WebSocket.OPEN)
    ws.send(JSON.stringify({code:code,format:fmt,enter:pressEnter,ts:now}));
}
function toggleEnter(){
  pressEnter=!pressEnter;
  var b=document.getElementById('etb');
  b.textContent=pressEnter?'\u0412\u041a\u041b':'\u0412\u042b\u041a\u041b';
  b.classList.toggle('on',pressEnter);
}

connect();
startCamera();
</script>
</body>
</html>"""
    )

# ══════════════════════════════════════════════════════════════
# WebSocket + HTTP server (single port)
# ══════════════════════════════════════════════════════════════
import platform as _platform
_IS_MAC = _platform.system() == "Darwin"

# ── Клавиатурный ввод через pynput (HID уровень) ─────────────
try:
    from pynput.keyboard import Key, Controller as _KbController
    _kb = _KbController()
    _PYNPUT = True
except ImportError:
    _PYNPUT = False
    _kb = None

def _type_text(text, with_enter=False):
    """Печатает строку. На Mac через pynput (HID уровень)."""
    if not text and not with_enter:
        return
    if _PYNPUT:
        if text:
            _kb.type(text)
        if with_enter:
            time.sleep(0.05)
            _kb.press(Key.enter)
            _kb.release(Key.enter)
    elif _IS_MAC:
        import subprocess
        lines = []
        for ch in text:
            if ch.isupper():
                lines.append(f'keystroke "{ch.lower()}" using shift down')
            elif ch == '"':
                lines.append('keystroke quote')
            else:
                lines.append(f'keystroke "{ch}"')
        if with_enter:
            lines.append('key code 36')  # Return
        script = 'tell application "System Events"\n' + '\n'.join(lines) + '\nend tell'
        subprocess.run(['osascript', '-e', script], capture_output=True)
    else:
        for ch in text:
            if ch.isupper():
                pyautogui.keyDown('shift'); pyautogui.press(ch.lower()); pyautogui.keyUp('shift')
            else:
                pyautogui.press(ch)
            time.sleep(KEY_INTERVAL)
        if with_enter:
            pyautogui.press('enter')


def type_code(code, press_enter):
    time.sleep(TYPE_DELAY)
    try:
        GS = '\x1d'
        if GS in code:
            parts = code.split(GS)
            print(f"  {D}[GS×{len(parts)-1}] Печатаю {len(parts)} частей с F8 между ними{X}")
            for i, part in enumerate(parts):
                is_last = (i == len(parts) - 1)
                if part:
                    print(f"  {D}  → часть {i+1}/{len(parts)}: {len(part)} симв.{X}")
                    # На последней части сразу добавляем Enter — без паузы между ними
                    _type_text(part, with_enter=(is_last and press_enter))
                if not is_last:
                    print(f"  {D}  → F8{X}")
                    if _IS_MAC:
                        import subprocess
                        subprocess.run(['osascript', '-e',
                            'tell application "System Events" to key code 100'],
                            capture_output=True)
                    elif _PYNPUT:
                        _kb.press(Key.f8); _kb.release(Key.f8)
                    else:
                        pyautogui.press('f8')
                    time.sleep(0.05)
        else:
            _type_text(code, with_enter=press_enter)
        if press_enter:
            print(f"  {D}  → Enter отправлен{X}")
        print(f"  {G}  ✓ Ввод завершён{X}")
    except Exception as e:
        print(f"  {R}Ошибка ввода: {e}{X}")


async def ws_handler(websocket):
    global scan_count
    addr = websocket.remote_address[0]
    connected_clients.add(websocket)
    print(f"  {G}\u2713 Телефон подключён: {addr}{X}")
    try:
        async for msg in websocket:
            data = json.loads(msg)
            code = data.get("code","")
            fmt  = data.get("format","")
            if code:
                scan_count += 1
                ts = time.strftime("%H:%M:%S")
                tag = f"{D}[{fmt}]{X} " if fmt else ""
                gs_info = f" {D}[GS×{code.count(chr(29))}]{X}" if chr(29) in code else ""
                print(f"  {D}{ts}{X}  {tag}{G}{B}{code.replace(chr(29), '⊕')}{X}{gs_info}")
                threading.Thread(target=type_code,args=(code,data.get("enter",True)),daemon=True).start()
    except Exception: pass
    finally:
        connected_clients.discard(websocket)
        print(f"  {Y}\u26a1 Телефон отключился: {addr}{X}")

async def process_request(path, request_headers):
    """HTTP handler: страница, wasm файл, или WebSocket."""
    if path == "/ws":
        return None  # WebSocket upgrade
    if path == "/zxing.wasm":
        return (
            http.HTTPStatus.OK,
            [("Content-Type","application/wasm"),
             ("Content-Length", str(len(ZXING_WASM))),
             ("Cache-Control","public, max-age=86400")],
            ZXING_WASM,
        )
    # Default: HTML page
    html = get_html(_server_ip).encode("utf-8")
    return (
        http.HTTPStatus.OK,
        [("Content-Type","text/html; charset=utf-8"),
         ("Content-Length", str(len(html)))],
        html,
    )

async def start_server(ssl_ctx):
    async with serve(ws_handler, "0.0.0.0", PORT, ssl=ssl_ctx,
                     process_request=process_request,
                     ping_interval=30, ping_timeout=60) as server:
        await asyncio.Future()

# ══════════════════════════════════════════════════════════════
# Utils
# ══════════════════════════════════════════════════════════════
def get_ip():
    try:
        s=socket.socket(socket.AF_INET,socket.SOCK_DGRAM)
        s.connect(("8.8.8.8",80)); ip=s.getsockname()[0]; s.close(); return ip
    except: return "127.0.0.1"

def print_qr(url):
    try:
        import qrcode
        qr=qrcode.QRCode(border=1,error_correction=qrcode.constants.ERROR_CORRECT_L)
        qr.add_data(url); qr.make(fit=True)
        m=qr.get_matrix()
        print()
        for y in range(0,len(m),2):
            top=m[y]; bot=m[y+1] if y+1<len(m) else [False]*len(top)
            line="  "
            for t,b in zip(top,bot):
                if t and b: line+="\u2588"
                elif t:     line+="\u2580"
                elif b:     line+="\u2584"
                else:       line+=" "
            print(line)
        print()
    except ImportError:
        print(f"  {D}(pip install qrcode для QR-кода){X}")

def banner(ip):
    url=f"https://{ip}:{PORT}"
    os.system('cls' if os.name=='nt' else 'clear')
    print(f"\n{C}{B}  InsideScan  \u00b7  локальный HTTPS{X}\n")
    print(f"  {B}Открой на телефоне:{X}  {G}{B}{url}{X}")
    print_qr(url)
    print(f"  {Y}\u26a0  Нажми «Подробнее» \u2192 «Перейти на сайт»{X}")
    print(f"  {D}   (предупреждение о сертификате — нормально){X}\n")
    enter_str = "ВКЛ" if PRESS_ENTER else "ВЫКЛ"
    print(f"  {D}Порт: {PORT}  |  Enter: {enter_str}{X}")
    sep = "─" * 44
    print(f"\n{D}{sep}{X}")
    print(f"  {'ВРЕМЯ':<10} {'ТИП':<16} КОД")
    print(f"{D}{sep}{X}")

def main():
    global _server_ip
    ip=get_ip(); _server_ip=ip
    if not create_cert(ip): sys.exit(1)
    ssl_ctx=make_ssl_ctx()
    banner(ip)
    try:
        asyncio.run(start_server(ssl_ctx))
    except KeyboardInterrupt:
        print(f"\n\n{D}Остановлено. Кодов: {scan_count}{X}\n")
        for f in (CERT_FILE,KEY_FILE):
            try: os.remove(f)
            except: pass

if __name__=="__main__":
    main()
